FormScriptItem.Script:
// Form Validation for Shopping Cart as part of fpOnline

/* 
CONTROL NAME        | TYPE          | EVENT
--------------------+---------------+------
Amount Received     | Currency      | Blur
Check Number^       | Blank         | Blur
Payer Name          | Blank         | Blur
Mailing Country     | Dropdown      | Blur
Mailing Street      | Blank         | Blur
Mailing City        | Blank         | Blur
Mailing Zip Code    | Zip Required  | Blur
Mailing State       | DropDown      | Blur
Billing Country     | Dropdown      | Blur
Billing Street      | Blank         | Blur
Billing City        | Blank         | Blur
Billing Zip Code    | Zip Required  | Blur
Billing State       | DropDown      | Blur
Payment Date        | TodayorBefore | Blur
Payment Type        | DropDown      | Blur
Received By         | Blank         | Blur

- ^ Corresponds to 'Transaction ID or Check Number' field
*/

// Pass in ControlName to validate a single item or nothing to validate everything.
var ErrorReporting = true;

var RunAll = false;
if (ControlName == null) {
  RunAll = true;
}

// Form Field Collections
const PAYMENT_DETAILS = 'Payment Details';

let errorMessage;

/*************************************
    BEGIN GENERATED VALIDATION CODE
**************************************/
//Amount Received - Field must have a number entered greater than 0
if ((ControlName == 'Amount Received' || ControlName == PAYMENT_DETAILS || RunAll) && !VV.Form.IsFieldReadOnly('Amount Received')) {
  if (VV.Form.Global.CentralNumericValidation(VV.Form.GetFieldValue('Amount Received'), 0, 'GreaterThan') == false) {
    VV.Form.SetValidationErrorMessageOnField('Amount Received', 'Amount Received must be entered in the form of a valid currency amount.');
    ErrorReporting = false;
  }
  else {
    VV.Form.ClearValidationErrorOnField('Amount Received');
  }
}
//Transaction ID or Check Number - Field that must be completed.
if ((ControlName == "Transaction ID or Check Number" || ControlName == PAYMENT_DETAILS || RunAll) && 
 !VV.Form.IsFieldReadOnly("Transaction ID or Check Number")) {
  if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue("Transaction ID or Check Number"), "Blank") == false) {
    VV.Form.SetValidationErrorMessageOnField("Transaction ID or Check Number", "Please complete the Transaction ID or Check Number field.");
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Transaction ID or Check Number");
  }
}
//Payer Name - Field that must be completed.
if ((ControlName == "Payer Name" || RunAll) && !VV.Form.IsFieldReadOnly("Payer Name")) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue("Payer Name"),
      "Blank",
    ) == false
  ) {
    errorMessage = "Please complete the Payer Name field.";
    VV.Form.SetValidationErrorMessageOnField("Payer Name", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Payer Name");
  }
}

//***********MAILING ADDRESS FIELDS************/
// used to determine whether to run validation on city, state, zip, county
var MailingCountryIsUS = VV.Form.GetDropDownListItemValue("Mailing Country") == "United States";

//Mailing Country - DropDown must be selected.
if ((ControlName == "Mailing Country" || ControlName == "CopyMailingToBillingAddress" || RunAll) && !VV.Form.IsFieldReadOnly("Mailing Country")) {
  var isSelectItem =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Mailing Country"),
      "DDSelect",
    ) == false;
  var isBlank =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Mailing Country"),
      "Blank",
    ) ==
    false; /* added as a workaround to getddtext occasionally returning empty string - 7/14/2021 */
  if (isSelectItem || isBlank) {
    errorMessage = "Please make a selection from the Mailing Country dropdown.";
    VV.Form.SetValidationErrorMessageOnField("Mailing Country", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Mailing Country");
  }
}
//Mailing Street - Field that must be completed.
if ((ControlName == "Mailing Street" || ControlName == "CopyMailingToBillingAddress" || RunAll) && !VV.Form.IsFieldReadOnly("Mailing Street")) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue("Mailing Street"),
      "Blank",
    ) == false
  ) {
    errorMessage = "Please complete Address Line 1.";
    VV.Form.SetValidationErrorMessageOnField("Mailing Street", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Mailing Street");
  }
}
//Mailing City - Field that must be completed.
if (MailingCountryIsUS) {
  if ((ControlName == "Mailing City" || ControlName == "CopyMailingToBillingAddress" || RunAll) && !VV.Form.IsFieldReadOnly("Mailing City")) {
    if (
      VV.Form.Global.CentralValidation(
        VV.Form.GetFieldValue("Mailing City"),
        "Blank",
      ) == false
    ) {
      errorMessage = "Please complete the Mailing City field.";
      VV.Form.SetValidationErrorMessageOnField("Mailing City", errorMessage);
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField("Mailing City");
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Mailing City");
}
//Mailing Zip Code - Field that must be completed.
var enteredValue = VV.Form.GetFieldValue("Mailing Zip Code");
var formattedVal = VV.Form.Global.FormatZipCode(enteredValue);

if (MailingCountryIsUS && !VV.Form.IsFieldReadOnly("Mailing Zip Code")) {
  if (formattedVal != enteredValue) {
    VV.Form.SetFieldValue("Mailing Zip Code", formattedVal);
  } else {
    if (ControlName == "Mailing Zip Code" || ControlName == "CopyMailingToBillingAddress" || RunAll) {
      if (
        VV.Form.Global.CentralValidation(
          VV.Form.GetFieldValue("Mailing Zip Code"),
          "Zip",
        ) == false
      ) {
        VV.Form.SetValidationErrorMessageOnField(
          "Mailing Zip Code",
          "A zip code must be entered, and it must be in the format of XXXXX or XXXXX-XXXX.",
        );
        ErrorReporting = false;
      } else {
        VV.Form.ClearValidationErrorOnField("Mailing Zip Code");
      }
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Mailing Zip Code");
}
//Mailing State - DropDown must be selected.
if (MailingCountryIsUS) {
  if ((ControlName == "Mailing State" || ControlName == "CopyMailingToBillingAddress" || RunAll) && 
   !VV.Form.IsFieldReadOnly("Mailing State")) {
    var isSelectItem =
      VV.Form.Global.CentralValidation(
        VV.Form.getDropDownListText("Mailing State"),
        "DDSelect",
      ) == false;
    var isBlank =
      VV.Form.Global.CentralValidation(
        VV.Form.getDropDownListText("Mailing State"),
        "Blank",
      ) ==
      false; /* added as a workaround to getddtext occasionally returning empty string - 7/14/2021 */
    if (isSelectItem || isBlank) {
      VV.Form.SetValidationErrorMessageOnField(
        "Mailing State",
        "Please make a selection from the Mailing State dropdown.",
      );
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField("Mailing State");
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Mailing State");
}

//***********Billing ADDRESS FIELDS************/
// used to determine whether to run validation on city, state, zip, county
var BillingCountryIsUS = VV.Form.GetDropDownListItemValue("Billing Country") == "United States";

//Billing Country - DropDown must be selected.
if ((ControlName == "Billing Country" || RunAll) && !VV.Form.IsFieldReadOnly("Billing Country")) {
  var isSelectItem =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Billing Country"),
      "DDSelect",
    ) == false;
  var isBlank =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Billing Country"),
      "Blank",
    ) ==
    false; /* added as a workaround to getddtext occasionally returning empty string - 7/14/2021 */
  if (isSelectItem || isBlank) {
    errorMessage = "Please make a selection from the Billing Country dropdown.";
    VV.Form.SetValidationErrorMessageOnField("Billing Country", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Billing Country");
  }
}
//Billing Street - Field that must be completed.
if ((ControlName == "Billing Street" || RunAll) && !VV.Form.IsFieldReadOnly("Billing Street")) {
  if (
    VV.Form.Global.CentralValidation(
      VV.Form.GetFieldValue("Billing Street"),
      "Blank",
    ) == false
  ) {
    errorMessage = "Please complete Address Line 1.";
    VV.Form.SetValidationErrorMessageOnField("Billing Street", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Billing Street");
  }
}
//Billing City - Field that must be completed.
if (BillingCountryIsUS) {
  if ((ControlName == "Billing City" || RunAll) && !VV.Form.IsFieldReadOnly("Billing City")) {
    if (
      VV.Form.Global.CentralValidation(
        VV.Form.GetFieldValue("Billing City"),
        "Blank",
      ) == false
    ) {
      errorMessage = "Please complete the Billing City field.";
      VV.Form.SetValidationErrorMessageOnField("Billing City", errorMessage);
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField("Billing City");
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Billing City");
}
//Billing Zip Code - Field that must be completed.
var enteredValue = VV.Form.GetFieldValue("Billing Zip Code");
var formattedVal = VV.Form.Global.FormatZipCode(enteredValue);

if (BillingCountryIsUS && !VV.Form.IsFieldReadOnly("Billing Zip Code")) {
  if (formattedVal != enteredValue) {
    VV.Form.SetFieldValue("Billing Zip Code", formattedVal);
  } else {
    if (ControlName == "Billing Zip Code" || RunAll) {
      if (
        VV.Form.Global.CentralValidation(
          VV.Form.GetFieldValue("Billing Zip Code"),
          "Zip",
        ) == false
      ) {
        VV.Form.SetValidationErrorMessageOnField(
          "Billing Zip Code",
          "A zip code must be entered, and it must be in the format of XXXXX or XXXXX-XXXX.",
        );
        ErrorReporting = false;
      } else {
        VV.Form.ClearValidationErrorOnField("Billing Zip Code");
      }
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Billing Zip Code");
}
//Billing State - DropDown must be selected.
if (BillingCountryIsUS) {
  if ((ControlName == "Billing State" || RunAll) && !VV.Form.IsFieldReadOnly("Billing State")) {
    var isSelectItem =
      VV.Form.Global.CentralValidation(
        VV.Form.getDropDownListText("Billing State"),
        "DDSelect",
      ) == false;
    var isBlank =
      VV.Form.Global.CentralValidation(
        VV.Form.getDropDownListText("Billing State"),
        "Blank",
      ) ==
      false; /* added as a workaround to getddtext occasionally returning empty string */
    if (isSelectItem || isBlank) {
      VV.Form.SetValidationErrorMessageOnField(
        "Billing State",
        "Please make a selection from the Billing State dropdown.",
      );
      ErrorReporting = false;
    } else {
      VV.Form.ClearValidationErrorOnField("Billing State");
    }
  }
} else {
  VV.Form.ClearValidationErrorOnField("Billing State");
}
//Payment Date - Date must be today or before today
if ((ControlName == 'Payment Date' || ControlName == PAYMENT_DETAILS || RunAll) && !VV.Form.IsFieldReadOnly('Payment Date')) {
  if (VV.Form.Global.CentralDateValidation(VV.Form.GetFieldValue('Payment Date'), 'TodayorBefore') == false) {
      VV.Form.SetValidationErrorMessageOnField('Payment Date', 'Payment Date must be today or before today.');
      ErrorReporting = false;
  }
  else {
      VV.Form.ClearValidationErrorOnField('Payment Date');
  }
}
//Payment Type - DropDown must be selected.
if ((ControlName == "Payment Type" || RunAll) && !VV.Form.IsFieldReadOnly("Payment Type")) {
  var isSelectItem =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Payment Type"),
      "DDSelect",
    ) == false;
  var isBlank =
    VV.Form.Global.CentralValidation(
      VV.Form.getDropDownListText("Payment Type"),
      "Blank",
    ) ==
    false; /* added as a workaround to getddtext occasionally returning empty string - 7/14/2021 */
  if (isSelectItem || isBlank) {
    errorMessage = "Please make a selection from the Payment Type dropdown.";
    VV.Form.SetValidationErrorMessageOnField("Payment Type", errorMessage);
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Payment Type");
  }
}
//Received By - Field that must be completed.
if ((ControlName == "Received By" || ControlName == PAYMENT_DETAILS || RunAll) && !VV.Form.IsFieldReadOnly("Received By")) {
  if (VV.Form.Global.CentralValidation(VV.Form.GetFieldValue("Received By"), "Blank") == false) {
    VV.Form.SetValidationErrorMessageOnField("Received By", "Please complete the Received By field.");
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField("Received By");
  }
}

return ErrorReporting;

/* VerifyExistingCart for Shopping Cart - Calls a webservice that determines the action to take on the current unpaid cart

   Parameters: none
   Return Value: (Promise<Object>) Resolves to the object returned by the webservice
*/
const websvcName = 'ShoppingCartVerifyExistingCart';
const deferred = $.Deferred();
let CallServerSide = function () {
    VV.Form.ShowLoadingPanel();
    const formData = VV.Form.Global.GetFormData(['Individual ID', 'Form ID']);

    formData.push({
        name: 'User ID',
        value: VV.Form.FormUserID,
    });

    //Following will prepare the collection and send with call to server side script.
    let data = JSON.stringify(formData);
    let requestObject = $.ajax({
        type: "POST",
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
        contentType: `application/json; charset=utf-8`,
        data: data,
    });

    return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
    VV.Form.HideLoadingPanel();
    let messageData = "";
    if (typeof resp.status != "undefined") {
        messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        displayErrorModal(messageData);
    } else if (typeof resp.statusCode != "undefined") {
        messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
        displayErrorModal(messageData);
    } else if (resp.meta.status == "200") {
        if (resp.data[0] != "undefined") {
            if (resp.data[0] == "Success") {
                const returnObj = resp.data[2];
                deferred.resolve(returnObj);
            } else if (resp.data[0] == "Error") {
                messageData = `An error was encountered. ${resp.data[1]}`;
                displayErrorModal(messageData);
            } else {
                messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
                displayErrorModal(messageData);
            }
        } else {
            messageData = "The status of the response returned as undefined.";
            displayErrorModal(messageData);
        }
    } else {
        messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
        displayErrorModal(messageData);
    }

    // reject promise if not otherwise handled somehow
    if (deferred.state() !== 'resolved') {
        deferred.reject(messageData);
    }
});

function displayErrorModal(messageData, title='Error') {
    VV.Form.Global.DisplayModal({ Title: title, Icon: 'error', HtmlContent: messageData });
}

return deferred.promise();

// RemovePaymentItemsFromCart for Shopping Cart

const MAX_QUANTITY = 20;
const selectedItems = VV.Form.Global.DatagridFindSelectedRows("DG Payment Items");

if (selectedItems.length > 0 && selectedItems.length <= MAX_QUANTITY) {
  let confirmMessage = `Do you want to remove the selected Payment Item record(s) from this Shopping Cart?`;
  VV.Form.Global.DisplayModal({
    Icon: "question",
    Title: "Confirm",
    HtmlContent: confirmMessage,
    okFunction: fireWebSvc,
  });
} else if (selectedItems.length > 0 && selectedItems.length > MAX_QUANTITY) {
  let limitMessage = `Please select at most ${MAX_QUANTITY} records at a time.`;
  VV.Form.Global.DisplayModal({
    Icon: "warning",
    Title: "Warning",
    HtmlContent: limitMessage,
  });
  return;
} else {
  let selectOneMessage = `Please select at least one record to remove from this Shopping Cart.`;
  VV.Form.Global.DisplayModal({
    Icon: "warning",
    Title: "Warning",
    HtmlContent: selectOneMessage,
  });
  return; // exit function
}

function fireWebSvc() {
  let websvcName = "ShoppingCartAddRemoveItems";
  let CallServerSide = function () {
    VV.Form.ShowLoadingPanel();
    let formData = VV.Form.Global.GetFormData(["Individual ID"]);

    formData.push({
      name: 'Action',
      value: 'Remove'
    });

    formData.push({
      name: 'Notify User',
      value: notifyUser !== false ? 'True' : 'False'
    });

    formData.push({
      name: 'Shopping Cart ID',
      value: VV.Form.GetFieldValue("Form ID")
    });

    formData.push({
      name: 'Shopping Cart GUID',
      value: VV.Form.DataID
    });

    formData.push({
      name: 'Selected Items',
      value: selectedItems
    });

    //Following will prepare the collection and send with call to server side script.
    let data = JSON.stringify(formData);
    let requestObject = $.ajax({
      type: "POST",
      url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
      contentType: `application/json; charset=utf-8`,
      data: data,
    });

    return requestObject;
  };

  $.when(CallServerSide()).always(function (resp) {
    VV.Form.HideLoadingPanel();
    let messageData = "";
    if (typeof resp.status != "undefined") {
      messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
      displayErrorModal(messageData);
    } else if (typeof resp.statusCode != "undefined") {
      messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
      displayErrorModal(messageData);
    } else if (resp.meta.status == "200") {
      if (resp.data[0] != "undefined") {
        if (resp.data[0] == "Success") {
          const responseMsg = resp.data[1];
          if (responseMsg == 'Related Items Found') {
            // There were related Payment Item(s) for the selected item(s), so display a notice to the user
            const relatedPaymentItemData = resp.data[2];
            VV.Form.Template.DisplayRelatedItems('Remove', relatedPaymentItemData);
          }
          else {
            // The action was completed, so update fields, save form, display message, and refresh grids
            let totalAmountDue = resp.data[2].totalAmountDue;

            Promise.all([
              VV.Form.SetFieldValue("Total Amount", totalAmountDue),
              VV.Form.SetFieldValue("Items Removed", "Select Item", false)
            ]).then(function() {
              return VV.Form.DoAjaxFormSave()
            }).then(function() {
              return VV.Form.Global.DisplayModal({
                Icon: "success",
                Title: "Success",
                HtmlContent: `The Payment Item and related fees have been successfully removed from this cart.`,
              });
            }).then(function() {
              VV.Form.Global.RefreshFormElements();
            });
          }
        } else if (resp.data[0] == "Error") {
          messageData = `An error was encountered. ${resp.data[1]}`;
          displayErrorModal(messageData);
        } else {
          messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
          displayErrorModal(messageData);
        }
      } else {
        messageData = "The status of the response returned as undefined.";
        displayErrorModal(messageData);
      }
    } else {
      messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
      displayErrorModal(messageData);
    }
  });
}

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: "Error",
    Icon: "error",
    HtmlContent: messageData,
  });
}

/** SetupHPPResponseHandler for Shopping Cart
 * - Parameters:    departmentName: (String) The name of the department belonging to the given Program Office
                    officeName:     (String) The name of the program office associated with the fees for the Shopping Cart

 * - Purpose:       Defines a callback function for SnapPay to use upon receiving a response, generates the target field as a 
 *                  hidden field to place this response, and returns the identity of this function and input field
 * - Revision Notes:
 *      01/13/2025 - John Sevilla: Script migrated.
 */

const webServiceName = 'ShoppingCartHandleHPPResponse';
const formName = 'Shopping Cart';
const callbackFuncName = 'handleExternalPaymentResponse';
const hiddenInputID = 'hpp_response';

// Create the hidden, target field and append it to the document body (remove it if it already exists)
$('input#' + hiddenInputID).remove();
const target = $(`<input type="hidden" id="${hiddenInputID}" name="${hiddenInputID}" />`);
$(document.body).append(target);

// Assign the callback function to the current window's global context
window[callbackFuncName] = function (error, result) {
    if (error) {
        // An error occurred, so log the error to the console and notify the user
        console.error(error);

        // Evaluate the error returned to send the appropriate error message
        let errorMessage = null;
        errorMessage = (error instanceof Error) ? error.message : null;
        errorMessage = errorMessage || (typeof error == 'string' ? error : null);
        errorMessage = errorMessage || (error && error.message ? error.message : null);
        errorMessage = errorMessage || (error && error.msg ? error.msg : null);
        errorMessage = errorMessage || JSON.stringify(error);

        const errorHTML = '<p>An error occurred:</p>' + '<br />' + `<p>${errorMessage}</p>`;
        Swal.fire({
            icon: 'error',
            title: result.status,
            html: errorHTML,
            showConfirmButton: true,
            showCancelButton: false,
            showDenyButton: false,
            confirmButtonText: 'OK'
        }).then((result) => {
            // Regardless of the user's action, close the modal
            Swal.closeModal();
        });
    }
    else if (result) {
        // Data was returned, so save the provided request parameters + response, and handle the response by calling the web service
        const requestText = document.querySelector(`script[data-target='#${hiddenInputID}']`).outerHTML;
        const targetResp = document.querySelector('input#' + hiddenInputID).value;

        VV.Form.ShowLoadingPanel();

        Promise.all([
            VV.Form.SetFieldValue('Payment Gateway Request', requestText),
            VV.Form.SetFieldValue('Payment Gateway Response', targetResp)
        ]).then(() => VV.Form.DoAjaxFormSave()).then(() => {
            // Form Field Names
            const FORM_ID = 'Form ID';
            const PAYER_NAME = 'Payer Name';

            const formData = [];

            formData.push({
                name: FORM_ID,
                value: VV.Form.GetFieldValue(FORM_ID)
            });

            formData.push({
                name: PAYER_NAME,
                value: VV.Form.GetFieldValue(PAYER_NAME)
            });

            formData.push({
                name: 'Department Name',
                value: departmentName
            });

            formData.push({
                name: 'Program Office Name',
                value: officeName
            });

            formData.push({
                name: 'HPP Request Text',
                value: requestText
            });

            formData.push({
                name: 'HPP Response JSON',
                value: result.response
            });

            // Parse the data as a JSON string
            const data = JSON.stringify(formData);

            const requestObject = $.ajax({
                type: 'POST',
                url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
                contentType: 'application/json; charset=utf-8',
                data: data,
                success: '',
                error: '',
            });

            $.when(requestObject).always(handleResponse);
        });
    }
    else {
        // Nothing was returned in the response
        // NOTE: This should never happen, but it is handled nonetheless
        VV.Form.Global.DisplayMessaging('No response was received from the Payment Gateway.', formName);
    }
}

// Always return the callback function name and input field selector
return {
    callbackFuncName:   callbackFuncName,
    targetSelector:     '#' + hiddenInputID
};

function handleResponse(resp) {
    VV.Form.HideLoadingPanel();

    if (typeof resp.status != 'undefined') {
        message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    } else if (typeof resp.statusCode != 'undefined') {
        message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
    } else if (resp.meta.status == '200') {
        if (resp.data[0] != undefined) {
            const responseStatus = resp.data[0];
            switch(responseStatus) 
            {
                case 'Success':
                    VV.Form.HideLoadingPanel();
                    const result = resp.data[2];
                    // NOTE: The result can be `null` if the payment was cancelled by the user; in which case, nothing should be displayed
                    if (result && (result.status == 'Success' || result.status == 'Error')) {
                        const isSuccess = result.status == 'Success';
                        const OKAY_BTN_TEXT = 'OK';

                        let modalHTML = '<p>' + result.message;
                        modalHTML += (isSuccess ? `<br/><br/>No further changes can be applied. You may click "${OKAY_BTN_TEXT}" or outside of this modal to exit the ${formName}, or close the ${formName} tab manually otherwise.` : '');
                        modalHTML += '</p>';

                        const swalOptions = {
                            icon: isSuccess ? 'success' : 'error',
                            title: result.status,
                            html:  modalHTML,
                            showConfirmButton: true,
                            showCancelButton: false,
                            showDenyButton: false,
                            confirmButtonText: OKAY_BTN_TEXT
                        };

                        let fieldsToSet = [];
                        if (isSuccess) {
                            // The transaction was successful, so communicate that to the user and set field values based on the response
                            fieldsToSet = result.fields.map((fieldData) => VV.Form.SetFieldValue(fieldData.name, fieldData.value));
                        }

                        // Set any fields, save the form, and then display a modal to the user
                        Promise.all(fieldsToSet).then(() => VV.Form.DoAjaxFormSave()).then(() => Swal.fire(swalOptions)).then((result) => {
                            // Regardless of the user's action, close the modal
                            Swal.closeModal();
                            if (isSuccess) {
                                // Attempt to close the current window since no further actions can be made by the user
                                // NOTE: In certain situations (opening from a direct formview link), the window is blocked from being closed by the browser
                                window.close();
                            }
                        });
                    }

                    break;
                case 'Error':
                    message = `An error was encountered. ${resp.data[1]}`;
                    VV.Form.Global.DisplayMessaging(message, formName);
                    VV.Form.HideLoadingPanel();
                    break;
                default:
                    message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                    VV.Form.Global.DisplayMessaging(message, formName);
                    VV.Form.HideLoadingPanel();
                    break;
            }
        } else {
            message = 'The status of the response returned as undefined.';
            VV.Form.Global.DisplayMessaging(message, formName);
            VV.Form.HideLoadingPanel();
        }
    } else {
        message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
        VV.Form.Global.DisplayMessaging(message, formName);
        VV.Form.HideLoadingPanel();
    }
}

