/** LaunchPayMenu for Shopping Cart
 * - Parameters:    transactionDetails (Object) - Contains properties used to call the HWP form and specificy recipients / transaction options
 * - Purpose:       Displays a confirmation modal for the user to be redirected to the Electronic Bill Presentment & Payments (EBPP) "E-Bill", hosted web form (HWF)
 * - Revision Notes:
 *      01/13/2025 - John Sevilla: Script migrated.
 *      04/02/2025 - Ross Rhone added edits for orbipay payment gateway (Keybank / EBill)
 *      04/17/2025 - Adding call to handle payment response to update shopping cart payment section
 *      04/29/2025 - Ross Rhone added error checking for if oripay fires multiple event-check-outs that it will only
 *                   run the payment gateway for one event.
 *      04/29/2025 - Alfredo Scilabra: Update error message on Error Processing Payment
 *      10/16/2025 - Ross Rhone - Updated error handling
 *      12/04/2025 - Alfredo Scilabra - Added fee_amount to getFieldsToUpdate
 */

/* -------------------------------------------------------------------------- */
/*                           Configurable Variables                           */
/* -------------------------------------------------------------------------- */

/**
 * Holds every payment receipt generated in this browser session.
 * Useful for debugging, exporting, or feeding other UI components later.
 */
const paymentReceipts = [];

/* -------------------------------------------------------------------------- */
/*                              Helper Functions                              */
/* -------------------------------------------------------------------------- */

/**
 * Parses a JSON string or plain error string and retrieves the error code and message.
 * @param {string} errorInput - JSON string or plain error string
 * @returns {{ code: string, message: string }}
 */
function parseErrorMessage(errorInput) {
  if (typeof errorInput !== 'string') {
    console.error('Invalid input: not a string.');
    return { code: '', message: '' };
  }

  try {
    const data = JSON.parse(errorInput);

    if (data.errors?.length) {
      const { code = '', message = '' } = data.errors[0];
      return { code, message };
    }
  } catch (err) {
    // If JSON parsing fails, treat it as a simple plain text error message
    if (errorInput.trim()) {
      return { code: 'unknown_error', message: errorInput.trim() };
    }
    console.error('Invalid input format and empty string.');
  }

  return { code: '', message: '' };
}

/**
 * Creates the Orbipay SDK checkout form inside the SweetAlert container.
 */
function createCheckoutDiv() {
  try {
    if (document.getElementById('orbipay-checkout-form')) {
      console.log('Orbipay form is already displayed. Skipping creation.');
      return;
    }

    const container = Swal.getHtmlContainer().querySelector('#checkoutContainer');
    if (!container) {
      console.error('No #checkoutContainer found in SweetAlert HTML');
      return;
    }

    VV.Form.Template.EBillCheckoutHTML()
      .then((htmlString) => {
        const fragment = document.createRange().createContextualFragment(htmlString);
        container.appendChild(fragment);

        // Wait a moment for the script tag to be added to the DOM
        setTimeout(() => {
          const script = document.getElementById('orbipay-checkout-script');
          if (!script) {
            return showCheckoutError(
              new Error('Payment Gateway failed to initialize. Please refresh or contact support.')
            );
          }

          script.onerror = () => {
            showCheckoutError(
              new Error('Payment Gateway failed to initialize. Please refresh or contact support.')
            );
          };
        }, 300); // Let the DOM catch up
      })
      .catch((error) => {
        console.error('Error generating payment gateway checkout form HTML:', error);
        showCheckoutError(
          new Error('Unable to generate the payment gateway form. Please try again later.')
        );
      });
  } catch (error) {
    console.error('Error loading payment gateway checkout form:', error);
    showCheckoutError(
      new Error('Unable to generate the payment gateway form. Please try again later.')
    );
  }
}

/**
 * Low‑level wrapper around $.ajax that returns a native Promise.
 * Converts HTTP / network errors into rejections.
 * Converts non‑200 business responses into rejections, too.
 */
function callService(name, payload) {
  return new Promise((resolve, reject) => {
    $.ajax({
      type: 'POST',
      url: `${VV.BaseAppUrl}/api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${name}`,
      contentType: 'application/json',
      headers: { Accept: 'application/json' }, // <— explicit
      data: JSON.stringify(payload),
      timeout: 90000,
    })
      .done((resp) => {
        if (resp.meta?.status === 200) {
          resolve(resp);
        } else {
          reject(new Error(`Service ${name} returned status ${resp.meta?.status}`));
        }
      })
      .fail((jqXHR, textStatus, errorThrown) => {
        reject(new Error(errorThrown || textStatus));
      });
  });
}

/* -------------------------------------------------------------------------- */
/*                       Main code functions                                  */
/* -------------------------------------------------------------------------- */

/**
 * Pay with Orbipay and return the *receipt* object on success.
 * @param {Array<Object>} tokenData
 * @returns {Promise<Object>}
 */
function processPayment(tokenData) {
  return callService('OrbipayEBillProcessPayment', tokenData).then((resp) => {
    const gatewayStatus = resp.data?.[0];

    switch (gatewayStatus) {
      case 'Success':
        return resp.data[1]; // confirmation_number, payment_status, etc.

      case 'Error': {
        const { message } = parseErrorMessage(resp.data[1]);
        throw new Error(message || 'Orbipay reported an error.');
      }

      default:
        throw new Error(`Unexpected gateway status: ${gatewayStatus}`);
    }
  });
}

function hasFee(receipt) {
  if (!receipt) {
    return false;
  }

  // Safely get the 'fee' object
  const fee = receipt?.fee;
  const feeAmount = fee?.fee_amount;

  // Check if 'fee' exists, is an object, and has properties
  const feeExists = fee !== null && typeof fee === 'object' && Object.keys(fee).length > 0;

  // Check if 'fee_amount' exists and is not empty
  const feeAmountIsValid = feeAmount !== null && feeAmount !== '';

  return feeExists && feeAmountIsValid;
}

/**
 * Push the receipt to your internal micro‑service.
 * Returns the same receipt so the caller can keep chaining if desired.
 */
function getFieldsToUpdate(receipt) {
  let totalAmount;
  let feeAmount = 0;

  // Check if the first item has a 'fee' field
  if (receipt.length > 0) {
    if (hasFee(receipt[0])) {
      feeAmount = parseFloat(receipt[0].fee.fee_amount);
      totalAmount = parseFloat(receipt[0].amount) + feeAmount;
    } else {
      totalAmount = receipt[0].amount;
    }

    const fieldsToUpdate = [
      { name: 'payment_method', value: receipt[0].payment_method },
      { name: 'confirmation_number', value: receipt[0].confirmation_number },
      { name: 'amount', value: totalAmount },
      { name: 'currency_code', value: receipt[0].currency_code3d },
      { name: 'transactionID', value: receipt[0].payment_reference },
      { name: 'fee_amount', value: feeAmount },
    ];

    return callService('ShoppingCartGetPaymentFields', fieldsToUpdate).then((resp) => {
      const gatewayStatus = resp.data?.[0];

      switch (gatewayStatus) {
        case 'Success':
          const cartReceipt = resp.data[2];
          return { receipt, cartReceipt }; // or just `receipt`, your choice
        case 'Error': {
          const { message } = parseErrorMessage(resp.data[1]);
          throw new Error(message || 'Cart‑update error.');
        }
        default:
          throw new Error(`Unexpected gateway status: ${gatewayStatus}`);
      }
    });
  } else {
    throw new Error('Failed to get response from payment gateway.');
  }
}

function updateShoppingCartPaymentSection(result) {
  const paymentReceipt = result.paymentReceipt || result; // bare receipt or bundled
  const cartReceipt = result.cartReceipt; // may be undefined

  const isSuccess = cartReceipt?.status === 'Success';

  //Update the new values of the payment section!
  let fieldsToSet = [];
  if (isSuccess) {
    // The transaction was successful, so communicate that to the user and set field values based on the response
    fieldsToSet = result.cartReceipt.fields.map((fieldData) =>
      VV.Form.SetFieldValue(fieldData.name, fieldData.value)
    );
  }

  // Set any fields, save the form, and then display a modal to the user
  return Promise.all(fieldsToSet)
    .then(() => VV.Form.DoAjaxFormSave())
    .then(() => ({ paymentReceipt, cartReceipt }));
}

function neutralizeOrbipayForm() {
  const form = document.getElementById('orbipay-checkout-form');
  if (!form) return;

  form.removeAttribute('action');
  form.setAttribute('novalidate', 'novalidate');

  // Block both user and programmatic submits
  const blockSubmit = (e) => {
    e.preventDefault();
    e.stopImmediatePropagation();
    console.log('[orbipay] blocked auto-submit');
  };
  form.addEventListener('submit', blockSubmit, true);
  form.submit = () => console.log('[orbipay] prevented programmatic submit');
}

