let checkoutEventHandled = false;
let checkoutEventTimer = null;
let checkoutHandlerRegistered = false;

window.addEventListener(
  'checkout-event',
  function handleCheckoutEvent(event) {
    console.log('checkout-event received:', event);
    checkoutHandlerRegistered = true;

    if (checkoutEventHandled) {
      console.log('checkout-event already handled, ignoring duplicate.');
      return;
    }

    // If another event fired very close, reset the timer
    if (checkoutEventTimer) {
      clearTimeout(checkoutEventTimer);
    }

    // Set a small delay to absorb possible duplicate quick-firings
    checkoutEventTimer = setTimeout(() => {
      // Mark as handled
      checkoutEventHandled = true;

      // Remove the event listener manually (extra safety)
      window.removeEventListener('checkout-event', handleCheckoutEvent);

      const tokenData = [
        { name: 'token', value: event.detail.token },
        { name: 'digiSign', value: event.detail.digiSign },
        { name: 'customer_reference', value: event.detail.customer_reference },
        { name: 'customer_account_reference', value: event.detail.customer_account_reference },
        { name: 'individualId', value: individualID },
        { name: 'shoppingCartId', value: shoppingCartID },
      ];

      VV.Form.ShowLoadingPanel();

      console.log('Calling processPayment...');
      processPayment(tokenData)
        .then((receipt) => {
          // keep an in‑memory history of receipts
          paymentReceipts.push(receipt);
          return paymentReceipts; // pass it down the chain
        })
        .then(getFieldsToUpdate)
        .then(updateShoppingCartPaymentSection) // UI uses receipt
        .then((payload) => {
          console.log('Payment Gateway Response', payload);
          return payload;
        })
        .then(VV.Form.Template.DisplayPaymentCompleteModal)
        .catch(showErrorModal)
        .finally(() => VV.Form.HideLoadingPanel());
    }, 400); // Wait 400ms to ensure no other checkout events are fired
  },
  { once: true }
); //only run this once otherwise it will duplicate calls

