// ApplyPaymentForCheck for Shopping Cart
const webServiceName = 'ShoppingCartApplyPaymentForCheck';
const formName = 'Shopping Cart';
let message; // the message is set below

VV.Form.ShowLoadingPanel();

function CallServerSide() {
    // Fields Names
    const FORM_ID = 'Form ID';
    const AMOUNT_RECEIVED = 'Amount Received';

    const formData = [];

    formData.push({
        name:   FORM_ID,
        value:  VV.Form.GetFieldValue(FORM_ID)
    });

    formData.push({
        name:   AMOUNT_RECEIVED,
        value:  VV.Form.GetFieldValue(AMOUNT_RECEIVED)
    });

    // Parse the data as a JSON string
    const data = JSON.stringify(formData);

    const requestObject = $.ajax({
        type: 'POST',
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
        contentType: 'application/json; charset=utf-8',
        data: data,
        success: '',
        error: '',
    });

    return requestObject;
}

$.when(CallServerSide()).always(handleResponse);

function handleResponse(resp) {
    if (typeof resp.status != 'undefined') {
        message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    } else if (typeof resp.statusCode != 'undefined') {
        message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
    } else if (resp.meta.status == '200') {
        if (resp.data[0] != undefined) {
            if (resp.data[0] == 'Success') {
                VV.Form.HideLoadingPanel();
                message = resp.data[1];
                const receivedMatchesTotalOwed = resp.data[2];

                const OKAY_BTN_TEXT = 'OK';
                let modalObj = {
                    icon: receivedMatchesTotalOwed ? 'success' : 'error',
                    title: receivedMatchesTotalOwed ? 'Payment Successfully Applied' : 'Error',
                    html: '<p>' + message + '</p>',
                    showDenyButton: false,
                    showCancelButton: false,
                    showConfirmButton: true,
                    confirmButtonText: OKAY_BTN_TEXT
                };

                if (receivedMatchesTotalOwed) {
                    // Update the Shopping Cart as 'Paid' and save the form
                    VV.Form.SetFieldValue('Status', 'Paid', true).then(VV.Form.DoAjaxFormSave()).then(() => {
                        // Append additional information to the modal body and display the modal to the user
                        modalObj.html += `<br /><p><b>Click "${OKAY_BTN_TEXT}" or outside of this modal to exit the ${formName}.</b></p>`;
                        Swal.fire(modalObj).then((result) => {
                            // Regardless of the user's action, close the form window
                            window.close();
                        });
                    });
                }
                else {
                    // The amount received did not match the sum of unpaid Payment Items
                    Swal.fire(modalObj).then((result) => {
                        // Regardless of the user's action, close the modal
                        Swal.closeModal();
                    });
                }
            } else if (resp.data[0] == 'Error') {
                message = `An error was encountered. ${resp.data[1]}`;
                VV.Form.Global.DisplayMessaging(message, formName);
                VV.Form.HideLoadingPanel();
            } else {
                message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                VV.Form.Global.DisplayMessaging(message, formName);
                VV.Form.HideLoadingPanel();
            }
        } else {
            message = 'The status of the response returned as undefined.';
            VV.Form.Global.DisplayMessaging(message, formName);
            VV.Form.HideLoadingPanel();
        }
    } else {
        message = `The following unhandled response occurred while attempting to retrieve data on the server side get data logic. ${resp.data.error} <br>`;
        VV.Form.Global.DisplayMessaging(message, formName);
        VV.Form.HideLoadingPanel();
    }
}

