// VerifyAndManageCart for Shopping Cart - Calls a webservice (VerifyExistingCart) that determines the action to take on the current unpaid cart, performs the appropriate actions, finally firing the web service that manages items in the cart (ManageItems)
VV.Form.Template.VerifyExistingCart().then((returnObj) => {
  const { type } = returnObj;
  if (type === "CreateNewCart") {
    // populate info for creating a new cart
    const { individual } = returnObj;
    VV.Form.Global.SetFieldValuesFromObj({
      "Payer Name": `${individual['first Name']} ${individual['last Name']}`,
      "Mailing Country": individual["country"],
      "Mailing Street": individual["address Line 1"],
      "Mailing Street1": individual["address Line 2"],
      "Mailing Street2": individual["address Line 3"],
      "Mailing Zip Code": individual["zip Code"],
      "Mailing City": individual["city"],
      "Mailing State": individual["state Code"] || individual["state"] || 'Select Item', // state code may be falsy if code lookup failed
      "Individual ID": individual["dhDocID"],
      "Status": "Unpaid"
    }).then(() => {
      return VV.Form.DoAjaxFormSave(); // Note: important for form data to be committed for subsequent ManageItems call
    }).then(() => {
      // associate fees to cart and update/save form
      VV.Form.Template.ManageItems();
    });
  } else if (type === "GoToExistingCart") {
    // redirect to existing cart
    const shouldOpenInReadOnlyMode = false; // Set to false for regular mode
    const windowTarget = "_self"; // Open in the current window
    VV.Form.Global.OpenURLFromGUID(returnObj.shoppingCartGUID, shouldOpenInReadOnlyMode, windowTarget);
  } else if (type === 'OnExistingCart') {
    VV.Form.Template.ManageItems();
  } else {
    // warning message
    VV.Form.Global.DisplayModal({
      Icon: 'warning',
      Title: 'Unable to Retrieve Shopping Cart',
      HtmlContent: '<div style="height:75px">The system was unable to retrieve the shopping cart for the current user. Please check the context in which you are opening this form or contact a system administrator if this problem continues.</div>',
      allowOutsideClick: false,
      showConfirmButton: false,
    });
  }
});

